**Trick:** Use OpenAI's `tiktoken` library to count tokens locally before the API call.

```python
import tiktoken

def count_tokens(text: str, model: str = 'gpt-4o') -> int:
    enc = tiktoken.encoding_for_model(model)
    return len(enc.encode(text))

if count_tokens(my_prompt) > 3000:
    my_prompt = summarize(my_prompt)  # truncate or compress
```

**Tip:** Build a router that sends tasks to the cheapest model capable of handling them.

```python
def route_task(task_type: str, prompt: str):
    if task_type in ['classify', 'extract', 'reformat']:
        model = 'gpt-4o-mini'
    elif task_type in ['reason', 'plan', 'synthesize']:
        model = 'gpt-4o'
    return call_llm(model, prompt)
```

**Trick:** After every N turns, summarize the conversation so far and replace the raw history with that summary.

```python
def compress_history(messages: list, llm) -> list:
    summary = llm.invoke(
        f'Summarize this conversation in 3 sentences:\n{messages}'
    )
    return [{'role': 'system', 'content': f'Conversation so far: {summary}'}]

if len(messages) > 10:
    messages = compress_history(messages, llm)
```

**Tip:** Implement a supervisor-worker pattern where one agent routes and validates, and specialist agents only execute.

```python
# Supervisor decides routing
def supervisor(task: str) -> str:
    route = router_llm.invoke(f'Which agent should handle: {task}? Options: researcher, coder, writer')
    if 'researcher' in route:
        return researcher_agent.run(task)
    elif 'coder' in route:
        return coder_agent.run(task)
    return writer_agent.run(task)
```

**Fix:** Validate embeddings before upserting.

```python
import math

def is_valid_embedding(vec: list) -> bool:
    return (
        len(vec) > 0 and
        not any(math.isnan(v) for v in vec) and
        not all(v == 0 for v in vec)
    )

valid_upserts = [
    (id, vec, meta) for id, vec, meta in upsert_batch
    if is_valid_embedding(vec)
]
if len(valid_upserts) < len(upsert_batch):
    print(f'Dropped {len(upsert_batch) - len(valid_upserts)} invalid vectors')
index.upsert(vectors=valid_upserts)
```

**Trick:** Use `@tool` with a Pydantic input schema.

```python
from langchain_core.tools import tool
from pydantic import BaseModel, Field

class SearchInput(BaseModel):
    query: str = Field(description='The search query')
    max_results: int = Field(default=5, ge=1, le=20, description='Number of results')
    language: str = Field(default='en', description='Language code')

@tool(args_schema=SearchInput)
def web_search(query: str, max_results: int = 5, language: str = 'en') -> str:
    '''Search the web for current information.'''
    return perform_search(query, max_results, language)
```

