**Tip:** Use the `tenacity` library for clean retry logic with exponential backoff.

```python
from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception_type
from openai import RateLimitError

@retry(
    retry=retry_if_exception_type(RateLimitError),
    wait=wait_exponential(multiplier=1, min=2, max=60),
    stop=stop_after_attempt(5)
)
def call_llm(messages: list) -> str:
    return client.chat.completions.create(
        model='gpt-4o',
        messages=messages
    )
```

**Trick:** Have a planner agent decompose the goal, then execute and verify each subtask independently.

```python
def decompose_task(goal: str, llm) -> list:
    plan = llm.invoke(
        f'Break this goal into 3-5 concrete, verifiable subtasks.\n'
        f'Each subtask must have a clear success criterion.\n'
        f'Goal: {goal}\n'
        f'Respond as a JSON list: [{{"task": ..., "success_criterion": ...}}]'
    )
    return json.loads(plan)

def execute_with_verification(subtasks: list, executor_agent):
    results = []
    for subtask in subtasks:
        result = executor_agent.run(subtask['task'])
        verified = verify_step(result, subtask['success_criterion'])
        if not verified:
            result = executor_agent.run(f'Retry: {subtask["task"]}. Previous attempt failed: {result}')
        results.append(result)
    return results
```

**Trick:** Add a fast routing step to classify whether retrieval is needed.

```python
def needs_retrieval(query: str, llm) -> bool:
    verdict = llm.invoke(
        f'Does answering this question require looking up specific company documents? '
        f'Reply only YES or NO.\n\nQuestion: {query}',
    )
    return 'YES' in verdict.upper()

def smart_answer(query: str):
    if needs_retrieval(query):
        docs = retriever.get_relevant_documents(query)
        return rag_chain.invoke({'context': docs, 'question': query})
    return direct_llm.invoke(query)
```
